<?php
require_once __DIR__ . '/membership.php';
require_once __DIR__ . '/notifications.php';
require_once __DIR__ . '/data.php';

function sf_ops_db(): ?PDO { return sf_db(); }
function sf_ops_table_exists(string $table): bool { $pdo=sf_ops_db(); if(!$pdo)return false; try{$s=$pdo->prepare('SHOW TABLES LIKE ?');$s->execute([$table]);return (bool)$s->fetchColumn();}catch(Throwable $e){return false;} }
function sf_ops_fetch_all(string $sql, array $params=[]): array { $pdo=sf_ops_db(); if(!$pdo)return []; try{$s=$pdo->prepare($sql);$s->execute($params);return $s->fetchAll()?:[];}catch(Throwable $e){error_log('Stonefellow ops fetch failed: '.$e->getMessage());return [];} }
function sf_ops_fetch_one(string $sql, array $params=[]): ?array { $rows=sf_ops_fetch_all($sql,$params); return $rows[0]??null; }
function sf_activity_icon(string $type): string { if(str_contains($type,'signup'))return 'member'; if(str_contains($type,'order')||str_contains($type,'purchase'))return 'commerce'; if(str_contains($type,'stream')||str_contains($type,'watch')||str_contains($type,'play'))return 'stream'; if(str_contains($type,'save')||str_contains($type,'library'))return 'library'; if(str_contains($type,'publish'))return 'publish'; if(str_contains($type,'payment'))return 'payment'; return 'activity'; }
function sf_activity_emit(array $event): int { $pdo=sf_ops_db(); if(!$pdo||!sf_ops_table_exists('member_activity_events'))return 0; $type=(string)($event['event_type']??'activity'); try{$s=$pdo->prepare("INSERT INTO member_activity_events (user_id, actor_name, event_type, event_group, content_type, content_id, title, detail, action_url, severity, metadata_json, occurred_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, COALESCE(?, NOW()))"); $s->execute([$event['user_id']??sf_current_user_id(),$event['actor_name']??null,$type,$event['event_group']??sf_activity_icon($type),$event['content_type']??null,$event['content_id']??null,$event['title']??ucfirst(str_replace('_',' ',$type)),$event['detail']??null,$event['action_url']??null,$event['severity']??'info',isset($event['metadata'])?json_encode($event['metadata'],JSON_UNESCAPED_SLASHES):null,$event['occurred_at']??null]); return (int)$pdo->lastInsertId();}catch(Throwable $e){error_log('Stonefellow activity emit failed: '.$e->getMessage());return 0;} }
function sf_activity_static_events(): array { global $catalogSongs,$videoCatalog; $rows=[]; foreach(array_slice($catalogSongs,0,3) as $song){$rows[]=['event_type'=>'song_stream_preview','event_group'=>'stream','title'=>'Song ready: '.($song['title']??'Stonefellow song'),'detail'=>'Audio player and signed preview/full stream payloads are available.','action_url'=>sf_url('song.php?slug='.urlencode((string)($song['slug']??''))),'severity'=>'info','occurred_at'=>date('Y-m-d H:i:s')];} foreach(array_slice($videoCatalog,0,3) as $video){$rows[]=['event_type'=>'video_watch_ready','event_group'=>'stream','title'=>'Video ready: '.($video['title']??'Stonefellow video'),'detail'=>'Secure signed video playback is registered.','action_url'=>sf_url('watch.php?slug='.urlencode((string)($video['slug']??''))),'severity'=>'info','occurred_at'=>date('Y-m-d H:i:s')];} return $rows; }
function sf_activity_recent(int $limit=80, string $group=''): array { $limit=max(1,min(200,$limit)); if(sf_ops_table_exists('member_activity_events')){ $where='';$params=[]; if($group!==''){$where='WHERE event_group=?';$params[]=$group;} return sf_ops_fetch_all("SELECT mae.*, u.email AS user_email, u.display_name FROM member_activity_events mae LEFT JOIN users u ON u.id=mae.user_id {$where} ORDER BY mae.occurred_at DESC, mae.id DESC LIMIT {$limit}",$params); } $rows=[]; if(sf_notify_ready()){ foreach(array_slice(sf_notify_recent_logs($limit),0,$limit) as $log){$rows[]=['event_type'=>'notification_'.$log['status'],'event_group'=>'notification','title'=>$log['subject']??'Notification','detail'=>($log['recipient_email']??'').' · '.($log['status']??''),'action_url'=>sf_url('admin/notifications.php'),'severity'=>($log['status']??'')==='failed'?'warning':'info','occurred_at'=>$log['created_at']??date('Y-m-d H:i:s')];} } return $rows ?: sf_activity_static_events(); }
function sf_activity_summary(int $days=30): array { $since=date('Y-m-d H:i:s',time()-($days*86400)); $summary=['events'=>0,'members'=>0,'streams'=>0,'commerce'=>0,'notifications'=>0,'library'=>0,'warnings'=>0]; if(sf_ops_table_exists('member_activity_events')){ $row=sf_ops_fetch_one("SELECT COUNT(*) AS events, COUNT(DISTINCT user_id) AS members, SUM(event_group='stream') AS streams, SUM(event_group='commerce') AS commerce, SUM(event_group='notification') AS notifications, SUM(event_group='library') AS library, SUM(severity IN ('warning','critical')) AS warnings FROM member_activity_events WHERE occurred_at >= ?",[$since])?:[]; foreach($summary as $k=>$v)$summary[$k]=(int)($row[$k]??0); return $summary; } $summary['events']=count(sf_activity_recent(200)); return $summary; }
function sf_ops_metric_counts(): array { return ['members'=>sf_ops_table_exists('users')?(int)(sf_ops_fetch_one('SELECT COUNT(*) AS total FROM users')['total']??0):0,'active_subscriptions'=>sf_ops_table_exists('user_subscriptions')?(int)(sf_ops_fetch_one("SELECT COUNT(*) AS total FROM user_subscriptions WHERE status IN ('active','trialing')")['total']??0):0,'open_orders'=>sf_ops_table_exists('orders')?(int)(sf_ops_fetch_one("SELECT COUNT(*) AS total FROM orders WHERE status NOT IN ('fulfilled','canceled','refunded')")['total']??0):0,'queued_notifications'=>sf_ops_table_exists('notification_logs')?(int)(sf_ops_fetch_one("SELECT COUNT(*) AS total FROM notification_logs WHERE status='queued'")['total']??0):0,'failed_notifications'=>sf_ops_table_exists('notification_logs')?(int)(sf_ops_fetch_one("SELECT COUNT(*) AS total FROM notification_logs WHERE status='failed'")['total']??0):0,'draft_content'=>sf_ops_table_exists('content_search_index')?(int)(sf_ops_fetch_one("SELECT COUNT(*) AS total FROM content_search_index WHERE status='draft'")['total']??0):0,'scheduled_content'=>sf_ops_table_exists('content_search_index')?(int)(sf_ops_fetch_one("SELECT COUNT(*) AS total FROM content_search_index WHERE status='scheduled'")['total']??0):0,'library_items'=>sf_ops_table_exists('member_library_items')?(int)(sf_ops_fetch_one('SELECT COUNT(*) AS total FROM member_library_items')['total']??0):0]; }
function sf_ops_tasks(): array { $tasks=[]; $counts=sf_ops_metric_counts(); if($counts['failed_notifications']>0)$tasks[]=['priority'=>'high','title'=>'Review failed notifications','detail'=>$counts['failed_notifications'].' notification sends failed.','url'=>sf_url('admin/notifications.php'),'status'=>'warning']; if($counts['queued_notifications']>20)$tasks[]=['priority'=>'medium','title'=>'Dispatch queued notifications','detail'=>$counts['queued_notifications'].' messages are queued.','url'=>sf_url('admin/notifications.php'),'status'=>'warning']; if($counts['open_orders']>0)$tasks[]=['priority'=>'high','title'=>'Fulfill open merch orders','detail'=>$counts['open_orders'].' order records are still open.','url'=>sf_url('admin/orders.php'),'status'=>'active']; if($counts['draft_content']>0)$tasks[]=['priority'=>'medium','title'=>'Review draft content','detail'=>$counts['draft_content'].' searchable content records are still drafts.','url'=>sf_url('admin/publishing.php'),'status'=>'draft']; if($counts['scheduled_content']>0)$tasks[]=['priority'=>'medium','title'=>'Check scheduled releases','detail'=>$counts['scheduled_content'].' items are scheduled.','url'=>sf_url('admin/release-schedule.php'),'status'=>'active']; if(sf_ops_table_exists('videos')){ $missing=(int)(sf_ops_fetch_one("SELECT COUNT(*) AS total FROM videos WHERE status='published' AND (poster_asset_id IS NULL OR slug IS NULL OR slug='')")['total']??0); if($missing>0)$tasks[]=['priority'=>'medium','title'=>'Complete published video metadata','detail'=>$missing.' published videos may need poster/slug details.','url'=>sf_url('admin/videos.php'),'status'=>'warning']; } if(sf_ops_table_exists('payment_gateway_settings')){ $active=(int)(sf_ops_fetch_one("SELECT COUNT(*) AS total FROM payment_gateway_settings WHERE status='active' AND provider IN ('stripe','paypal')")['total']??0); if($active===0)$tasks[]=['priority'=>'medium','title'=>'Confirm production payment gateway','detail'=>'Sandbox/local fallback remains active until a live gateway is enabled.','url'=>sf_url('admin/payment-gateways.php'),'status'=>'draft']; } if(!$tasks)$tasks[]=['priority'=>'low','title'=>'No urgent ops tasks','detail'=>'Core operations look clear. Continue content loading, QA, and launch checks.','url'=>sf_url('admin/launch-checklist.php'),'status'=>'active']; return $tasks; }
function sf_ops_recent_member_actions(): array { $rows=[]; if(sf_ops_table_exists('users')) foreach(sf_ops_fetch_all('SELECT id,email,display_name,created_at FROM users ORDER BY created_at DESC,id DESC LIMIT 8') as $u){$rows[]=['event_type'=>'member_signup','event_group'=>'member','title'=>'New member: '.($u['display_name']?:$u['email']),'detail'=>$u['email'],'action_url'=>sf_url('admin/members.php'),'occurred_at'=>$u['created_at']??date('Y-m-d H:i:s')];} if(sf_ops_table_exists('orders')) foreach(sf_ops_fetch_all('SELECT id,order_number,email,status,total_cents,created_at FROM orders ORDER BY created_at DESC,id DESC LIMIT 8') as $o){$rows[]=['event_type'=>'order_'.$o['status'],'event_group'=>'commerce','title'=>'Order '.$o['order_number'],'detail'=>($o['email']??'').' · $'.number_format(((int)($o['total_cents']??0))/100,2),'action_url'=>sf_url('admin/orders.php'),'occurred_at'=>$o['created_at']??date('Y-m-d H:i:s')];} return $rows; }
?>
